def solve():
    import sys
    data = sys.stdin.read().split()
    if not data:
        return
    N = int(data[0])
    X = int(data[1])
    arr = list(map(int, data[2:2+N]))
    lo, hi = 0, N-1
    found = False
    while lo <= hi:
        mid = (lo + hi) // 2
        if arr[mid] == X:
            found = True
            break
        elif arr[mid] < X:
            lo = mid + 1
        else:
            hi = mid - 1
    print('YES' if found else 'NO')

