import sys

def cross(ax, ay, bx, by, cx, cy):
    return (bx - ax) * (cy - ay) - (by - ay) * (cx - ax)

def main():
    data = sys.stdin.read().split()
    if not data:
        return
    x1, y1, x2, y2, x3, y3 = map(int, data[:6])
    x, y = map(int, data[6:8])
    S = abs(cross(x1, y1, x2, y2, x3, y3))
    S1 = abs(cross(x, y, x1, y1, x2, y2))
    S2 = abs(cross(x, y, x2, y2, x3, y3))
    S3 = abs(cross(x, y, x3, y3, x1, y1))
    if S == S1 + S2 + S3:
        print("YES")
    else:
        print("NO")

if __name__ == "__main__":
    main()

